sql:
SELECT COUNT(*)
FROM image_formats
WHERE is_vector = 1 AND is_lossless = 1;

SELECT format_name, max_resolution
FROM image_formats
WHERE is_vector = 1 AND is_lossless = 1;

SELECT app_name 
FROM software_applications 
WHERE developer = 'PNG Development Group' AND license_type = 'open source';

SELECT *
FROM access_logs
WHERE file_id IN (
    SELECT file_id
    FROM image_files
    WHERE format_id NOT IN (
        SELECT format_id
        FROM compatibility
    )
);

SELECT file_name, access_count
FROM image_files
WHERE format_id = (SELECT format_id FROM image_formats WHERE format_name = 'EMF') AND access_count > 1;

SELECT file_name, upload_date
FROM image_files
WHERE file_id = 1;

SELECT format_name
FROM image_formats
WHERE format_id IN (
  SELECT format_id
  FROM conversion_options
);

SELECT COUNT(*) AS TotalOrphanFiles
FROM image_files
WHERE format_id NOT IN (SELECT format_id FROM image_formats);

external_knowledge:
- "popular images" refers to images with an access count greater than 5;
- "not been deleted" means the `is_deleted` flag is 0;
- "looked at more than a few times" means the access count is more than 5.

